from notifications import send_confirmation, send_failure_notice

inventory = Inventory()
wallet = Wallet(balance=1000)


def create_order(order_id, sku, qty, price):
    """Pure business logic: reserve inventory and charge the wallet.
    Does NOT perform any external notification side-effects.
    """
    total = qty * price

    inventory.reserve(sku, qty)

    wallet.charge(total)

    return {"order_id": order_id, "charged": total, "reserved": qty}


def place_order(order_id, sku, qty, price):
    """Wrapper that calls the pure business function and then sends
    a confirmation. If notification fails, roll back the business
    operations and attempt to send a failure notice.
    """
    order = create_order(order_id, sku, qty, price)

    try:
        send_confirmation(order_id)
    except Exception as exc:
        # rollback business actions
        cancel_order(order_id, sku, qty, price)
        # attempt to notify about the failure (best-effort)
        try:
            send_failure_notice(order_id, str(exc))
        except Exception:
            # failure notice is best-effort; swallow to avoid masking original error
            pass
        # re-raise the original notification error so callers can react
        raise

    return order


def cancel_order(order_id, sku, qty, price):
    inventory.release(sku, qty)
    wallet.refund(qty * price)
